{"content": "#!/usr/bin/env python3
"""
🔍 SOVEREIGN Scraper v1.1 - Web Scraping Tool
Bisa search Google, scrape website, ambil data dari URL
"""

import sys
import json
import os
import re
from urllib.parse import quote_plus, urlparse, urljoin
from datetime import datetime

try:
    import requests
except ImportError:
    print("❌ Install dulu: pip install requests")
    sys.exit(1)

try:
    from bs4 import BeautifulSoup
except ImportError:
    print("❌ Install dulu: pip install beautifulsoup4")
    sys.exit(1)

# ============== CONFIG ==============
HEADERS = {
    "User-Agent": "Mozilla/5.0 (Linux; Android 13) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Mobile Safari/537.36",
    "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
    "Accept-Language": "en-US,en;q=0.5",
}

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
SAVE_DIR = os.path.join(SCRIPT_DIR, "results")
os.makedirs(SAVE_DIR, exist_ok=True)


def print_banner():
    print("""
╔═══════════════════════════════════════╗
║     🔍 SOVEREIGN SCRAPER v1.1        ║
║     Web Scraping & Search Tool       ║
╚═══════════════════════════════════════╝
    """)


def save_result(filename, data):
    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")

    json_path = os.path.join(SAVE_DIR, f"{filename}_{timestamp}.json")
    with open(json_path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

    txt_path = os.path.join(SAVE_DIR, f"{filename}_{timestamp}.txt")
    with open(txt_path, "w", encoding="utf-8") as f:
        if isinstance(data, list):
            for i, item in enumerate(data, 1):
                f.write(f"--- Hasil {i} ---\n")
                if isinstance(item, dict):
                    for k, v in item.items():
                        f.write(f"{k}: {v}\n")
                else:
                    f.write(f"{item}\n")
                f.write("\n")
        elif isinstance(data, dict):
            for k, v in data.items():
                if isinstance(v, str) and len(v) > 500:
                    f.write(f"{k}: {v[:500]}...\n")
                else:
                    f.write(f"{k}: {v}\n")
        else:
            f.write(str(data))

    print(f"\n💾 Disimpan:")
    print(f"   📄 {json_path}")
    print(f"   📄 {txt_path}")


# ============== FITUR 1: SEARCH via DuckDuckGo ==============
def search_duckduckgo(query, num_results=10):
    """Search via DuckDuckGo HTML (gak perlu API key)"""
    print(f"\n🔍 Searching DuckDuckGo: '{query}'")
    print(f"   Minta {num_results} hasil...\n")

    try:
        url = "https://html.duckduckgo.com/html/"
        data = {"q": query}
        resp = requests.post(url, data=data, headers=HEADERS, timeout=15)
        resp.raise_for_status()

        soup = BeautifulSoup(resp.text, "html.parser")
        results = []

        for i, result in enumerate(soup.select(".result"), 1):
            if i > num_results:
                break

            title_tag = result.select_one(".result__title a")
            snippet_tag = result.select_one(".result__snippet")

            if title_tag:
                title = title_tag.get_text(strip=True)
                href = title_tag.get("href", "")
                # DuckDuckGo sometimes wraps URLs
                if "uddg=" in href:
                    from urllib.parse import unquote, urlparse, parse_qs
                    parsed = urlparse(href)
                    params = parse_qs(parsed.query)
                    href = unquote(params.get("uddg", [href])[0])

                snippet = snippet_tag.get_text(strip=True) if snippet_tag else ""

                results.append({
                    "no": i,
                    "title": title,
                    "url": href,
                    "snippet": snippet
                })

                print(f"  [{i}] 🔗 {title}")
                print(f"      🌐 {href}")
                print(f"      📝 {snippet[:100]}...")
                print()

        print(f"📊 Total: {len(results)} hasil")
        return results

    except Exception as e:
        print(f"❌ Error search: {e}")
        return []


def search_google(query, num_results=10):
    """Search via Google scraping"""
    print(f"\n🔍 Searching Google: '{query}'")
    print(f"   Minta {num_results} hasil...\n")

    try:
        url = f"https://www.google.com/search?q={quote_plus(query)}&num={num_results}"
        resp = requests.get(url, headers=HEADERS, timeout=15)
        resp.raise_for_status()

        soup = BeautifulSoup(resp.text, "html.parser")
        results = []

        for i, g in enumerate(soup.select("div.g"), 1):
            if i > num_results:
                break

            a_tag = g.select_one("a")
            title_tag = g.select_one("h3")
            snippet_tag = g.select_one(".VwiC3b, .st")

            if a_tag and title_tag:
                title = title_tag.get_text(strip=True)
                href = a_tag.get("href", "")
                snippet = snippet_tag.get_text(strip=True) if snippet_tag else ""

                results.append({
                    "no": i,
                    "title": title,
                    "url": href,
                    "snippet": snippet
                })

                print(f"  [{i}] 🔗 {title}")
                print(f"      🌐 {href}")
                if snippet:
                    print(f"      📝 {snippet[:100]}...")
                print()

        if not results:
            print("  ⚠️ Google block. Coba pakai DuckDuckGo.")
            return search_duckduckgo(query, num_results)

        print(f"📊 Total: {len(results)} hasil")
        return results

    except Exception as e:
        print(f"  ⚠️ Google error: {e}. Switching to DuckDuckGo...")
        return search_duckduckgo(query, num_results)


# ============== FITUR 2: SCRAPE WEBSITE ==============
def scrape_website(url, extract="all"):
    print(f"\n🌐 Scraping: {url}")
    print(f"   Mode: {extract}\n")

    try:
        if not url.startswith("http"):
            url = "https://" + url

        response = requests.get(url, headers=HEADERS, timeout=15, allow_redirects=True)
        response.raise_for_status()
        response.encoding = response.apparent_encoding or 'utf-8'

        soup = BeautifulSoup(response.text, "html.parser")

        for s in soup(["script", "style", "noscript", "footer", "nav"]):
            s.decompose()

        result = {
            "url": response.url,
            "status": response.status_code,
        }

        # Title
        title_tag = soup.find("title")
        result["title"] = title_tag.get_text(strip=True) if title_tag else "-"
        print(f"📄 Title: {result['title']}")

        # Meta
        meta = soup.find("meta", attrs={"name": "description"})
        result["description"] = meta["content"] if meta and meta.get("content") else "-"

        if extract in ("all", "text"):
            text = soup.get_text(separator="\n", strip=True)
            lines = [l.strip() for l in text.splitlines() if l.strip() and len(l.strip()) > 2]
            result["text"] = "\n".join(lines[:200])  # limit 200 baris
            print(f"📝 Text: {len(result['text'])} karakter, {len(lines)} baris")

        if extract in ("all", "links"):
            links = []
            seen = set()
            for a in soup.find_all("a", href=True):
                href = a["href"]
                text = a.get_text(strip=True)[:100]
                if href.startswith("http") and text and href not in seen:
                    links.append({"text": text, "url": href})
                    seen.add(href)
            result["links"] = links
            print(f"🔗 Links: {len(links)} ditemukan")

        if extract in ("all", "images"):
            images = []
            for img in soup.find_all("img"):
                src = img.get("src") or img.get("data-src", "")
                if src and not src.startswith("data:"):
                    if not src.startswith("http"):
                        src = urljoin(url, src)
                    images.append({"src": src, "alt": img.get("alt", "")})
            result["images"] = images
            print(f"🖼️ Images: {len(images)} ditemukan")

        # Headers
        headers = {}
        for tag in ["h1", "h2", "h3"]:
            found = [h.get_text(strip=True) for h in soup.find_all(tag) if h.get_text(strip=True)]
            if found:
                headers[tag] = found[:10]
        result["headers"] = headers

        return result

    except requests.exceptions.RequestException as e:
        print(f"❌ Error: {e}")
        return {"url": url, "error": str(e)}


# ============== FITUR 3: CSS SELECTOR ==============
def fetch_data(url, selector):
    print(f"\n🎯 Fetching dari: {url}")
    print(f"   Selector: {selector}\n")

    try:
        if not url.startswith("http"):
            url = "https://" + url

        response = requests.get(url, headers=HEADERS, timeout=15)
        response.raise_for_status()
        response.encoding = response.apparent_encoding or 'utf-8'

        soup = BeautifulSoup(response.text, "html.parser")
        elements = soup.select(selector)

        results = []
        for i, el in enumerate(elements, 1):
            data = {
                "no": i,
                "tag": el.name,
                "text": el.get_text(strip=True)[:500]
            }
            if el.get("href"):
                data["href"] = el["href"]
            if el.get("src"):
                data["src"] = el["src"]
            for attr in ["class", "id", "alt"]:
                if el.get(attr):
                    data[attr] = str(el[attr])

            results.append(data)
            print(f"  [{i}] <{el.name}> {el.get_text(strip=True)[:80]}")

        print(f"\n📊 Total: {len(elements)} elemen")
        return results

    except Exception as e:
        print(f"❌ Error: {e}")
        return []


# ============== FITUR 4: MULTI SCRAPE ==============
def scrape_multiple(urls, extract="text"):
    print(f"\n📚 Scraping {len(urls)} halaman...\n")
    all_results = []
    for i, url in enumerate(urls, 1):
        print(f"--- [{i}/{len(urls)}] ---")
        result = scrape_website(url, extract)
        all_results.append(result)
    return all_results


# ============== FITUR 5: HEADERS CHECK ==============
def check_headers(url):
    """Check HTTP headers dari sebuah URL"""
    print(f"\n📋 HTTP Headers: {url}\n")
    try:
        if not url.startswith("http"):
            url = "https://" + url
        resp = requests.head(url, headers=HEADERS, timeout=10, allow_redirects=True)
        print(f"  Status: {resp.status_code}")
        print(f"  URL: {resp.url}")
        for k, v in resp.headers.items():
            print(f"  {k}: {v}")
        return dict(resp.headers)
    except Exception as e:
        print(f"❌ Error: {e}")
        return {}


# ============== INTERACTIVE MENU ==============
def interactive_menu():
    while True:
        print("""
╔═══════════════════════════════════════╗
║           📋 MENU UTAMA              ║
╠═══════════════════════════════════════╣
║  1. 🔍 Search (Google/DuckDuckGo)    ║
║  2. 🌐 Scrape Website (semua data)   ║
║  3. 🎯 Fetch Data (CSS Selector)     ║
║  4. 📚 Scrape Multiple URLs          ║
║  5. 📋 Cek HTTP Headers              ║
║  6. 📁 Lihat Hasil Tersimpan         ║
║  0. ❌ Keluar                        ║
╚═══════════════════════════════════════╝
        """)

        choice = input("  Pilih (0-6): ").strip()

        if choice == "1":
            query = input("  Search apa? ").strip()
            num = input("  Berapa hasil? [10]: ").strip()
            num = int(num) if num.isdigit() else 10
            engine = input("  Engine (g=Google/d=DuckDuckGo) [d]: ").strip().lower()

            if engine == "g":
                results = search_google(query, num)
            else:
                results = search_duckduckgo(query, num)

            if results:
                save_result("search", results)

        elif choice == "2":
            url = input("  URL: ").strip()
            extract = input("  Mode (all/text/links/images) [all]: ").strip() or "all"
            result = scrape_website(url, extract)
            if result:
                save_result("scrape", result)

        elif choice == "3":
            url = input("  URL: ").strip()
            selector = input("  CSS Selector (h1, .class, #id, a[href]): ").strip()
            if url and selector:
                results = fetch_data(url, selector)
                if results:
                    save_result("fetch", results)

        elif choice == "4":
            print("  Masukkan URL (ketik 'done' selesai):")
            urls = []
            while True:
                u = input("  URL: ").strip()
                if u.lower() == "done":
                    break
                urls.append(u)
            if urls:
                extract = input("  Mode (text/links/images) [text]: ").strip() or "text"
                results = scrape_multiple(urls, extract)
                save_result("multi_scrape", results)

        elif choice == "5":
            url = input("  URL: ").strip()
            check_headers(url)

        elif choice == "6":
            files = sorted(os.listdir(SAVE_DIR)) if os.path.exists(SAVE_DIR) else []
            if files:
                print(f"\n  📁 {SAVE_DIR}:")
                for f in files:
                    size = os.path.getsize(os.path.join(SAVE_DIR, f))
                    print(f"     📄 {f} ({size:,} bytes)")
            else:
                print("  Belum ada hasil tersimpan.")

        elif choice == "0":
            print("\n  👋 Bye!\n")
            break

        else:
            print("  ❌ Pilihan tidak valid!")

        input("\n  [Enter] Lanjut...")


# ============== MAIN ==============
if __name__ == "__main__":
    print_banner()

    if len(sys.argv) > 1:
        cmd = sys.argv[1]

        if cmd == "search":
            query = " ".join(sys.argv[2:])
            if not query:
                query = input("Search: ")
            search_duckduckgo(query)

        elif cmd == "scrape":
            url = sys.argv[2] if len(sys.argv) > 2 else input("URL: ")
            mode = sys.argv[3] if len(sys.argv) > 3 else "all"
            result = scrape_website(url, mode)
            if result:
                save_result("scrape", result)

        elif cmd == "fetch":
            url = sys.argv[2] if len(sys.argv) > 2 else input("URL: ")
            sel = sys.argv[3] if len(sys.argv) > 3 else input("Selector: ")
            fetch_data(url, sel)

        elif cmd == "headers":
            url = sys.argv[2] if len(sys.argv) > 2 else input("URL: ")
            check_headers(url)

        else:
            print("Commands: search, scrape, fetch, headers")
    else:
        interactive_menu()
